                  {activeState?.mensaje_whatsapp && (
                    <div>
                      <p className="font-medium text-foreground mb-1">WhatsApp de ejemplo</p>
                      <pre className="whitespace-pre-wrap rounded-lg bg-secondary/40 p-3 text-xs text-muted-foreground">
                        {activeState.mensaje_whatsapp}
                      </pre>
                    </div>
                  )}
